queries.sparql:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?questiontype WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasType_Of_Question ?child ; p:hasExam ?parent . } GROUP BY ?child }
  ?child p:questionType ?questiontype .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Exams } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?questiontype WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasType_Of_Question ?child ; p:hasExam ?parent . } GROUP BY ?child }
  ?child p:questionType ?questiontype .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Exams } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?examname ?questiontype WHERE {
  ?exam_type_of_question a :Exam_Type_Of_Question .
  ?type_of_question a :Type_Of_Question .
  ?exam_type_of_question p:hasType_Of_Question ?type_of_question .
  ?exam a :Exams .
  ?exam_type_of_question p:hasExam ?exam .
  ?exam p:examName ?examname .
  ?type_of_question p:questionType ?questiontype .
} }
}
